const Q_PHYSICS_2000=[{"id": "objective>Physics>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A catapult used to hold a stone of mass 500g is extended by 20cm with an applied force F. If the stone leaves with a velocity of 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, The value of F is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Topic: Elasticity <br/> Mass of stone, M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 500g = 0.5kg <br/> Extension, e = 20cm = 0.2m <br/> Applied force, F = Unknown <br/> Velocity of projection, V = 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> NOTE: The energy stored in the rubber of the catapault is converted the kinetic of the stone at the point of projection. <br/> <img src=\"2000/img1.png\" style=\"position:relative;max-width:100%;\"/> <br/> Therefore: <br/> Elastic potential Energy = K.E of the stone <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">Fe</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> Fe = mV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> F × 0.2 = 0.5 × 16 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> F × 0.2 = 800 <br/> F = 4000N = 4.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>N</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hand bag containing some load weighing 162N is carried by two students each holding the handle of the bag next to him. If each handle is pulled 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> to the vertical, find the force on each student arm.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">324N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">121N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2000/img2.png\" style=\"position:relative;max-width:100%;\"/> <br/> F = The force on each students arm. <br/>  <br/> You may want to divide the diagram <br/> <img src=\"2000/img3.png\" style=\"position:relative;max-width:100%;\"/> <br/> For the First Boy <br/> <img src=\"2000/img4.png\" style=\"position:relative;max-width:100%;\"/> <br/> For the second student <br/>  <br/> Note: F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = the vertical component of the force, F on each student's arm. <br/> Also note that the sum of the vertical components of the force on each students arm = 162N; this is because these two upward forces balance out the weight of the load (162N) <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = Fcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> + F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 162N ------------------------- (i) <br/> 2F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 162N <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 81N <br/> Fcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 81N <br/> F(0.5) = 81 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">81<hr size=\"1\" />0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">162N</td></tr></table></div> <br/> The force on each student's arm is 162N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. The frictional force is independent of the area of the surface in contact. <br/>  II. The frictional force depends on the nature of the surface in contact. <br/>  III. The frictional force depends on the speed of sliding. <br/>  IV. The frictional force is directly proportional to the normal reaction.  <br/>  Which combination of the above is true of sliding friction? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Laws of Solid Friction that we have include: <br/> Frictional force is independent of the surface area in contact. <br/> The frictional force depends on the nature of the surfaces in contact <br/> The frictional force depends on the normal reaction.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a ship sails from salt water into fresh water, the fraction of its volume above the water surface will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase then decrease</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the principle of flotation, a ship on any water displaces water of the same mass as itself. Note that the density of salt water is higher than that of fresh water.  <br/>  <br/> Density = Mass/Volume <br/> ρ = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">M</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">V</span> <br/> M = ρ ∗ V <br/>  <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span> = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span>,  <br/>  <br/> Therefore, <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span> * V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span> * V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span>*V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span><hr size=\"1\" />ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span></td></tr></table></div> <br/>  <br/> Since ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span> > ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span>, <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">fresh</span> > V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">salt</span> <br/>  <br/> The volume of displaced water in fresh water will be greater than that in salt water.  <br/>  <br/> As a result, the volume of the visible part of the ship above the fresh water will DECREASE. </div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A simple pendulum has a period of 17.0s. When the length is shortened by 1.5m, its period is 8.5s. Calculate the original length of the pendulum.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img5.png\" style=\"position:relative;max-width:100%;\"/> <img src=\"2000/img6.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">l<hr size=\"1\" />g</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> From this equation: <br/> T α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">L&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td></tr></table></div> <br/> From the question, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 17.0s, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 8.5, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 1.5 <br/> From ** <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">17<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8.5<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 1.5&nbsp;</span></td></tr></table></div> <br/>  <br/> Take the square of both sides <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">17<hr size=\"1\" />√L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">8.5<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>-1.5)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</td><td style=\"text-align:center;\"></span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">17<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8.5<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>-1.5</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">289<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">72.25<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>-1.5</td></tr></table></div> <br/> 72.25L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 289L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 433.5 <br/> 72.25L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - 289L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = -433.5 <br/> 216.75L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 433.5 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">433.5<hr size=\"1\" />216.75</td></tr></table></div> <br/> L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2 <br/> </div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At a <strong>fixed</strong> point below a liquid surface, the pressure downward is P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and the pressure upward is P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. It can be deduced that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> > P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> < P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ≤ P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Pascal's principle, pressure in a fluid is transmitted undiminished in all directions. At a fixed point below a liquid surface, the pressure downward (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) is balanced by the pressure upward (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). Therefore, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is equal to P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Its velocity is constant.  <br/> II. No work is done on the body.  <br/>  III. It has constant acceleration directed away from the centre.  <br/>  IV. The centripetal force is directed towards the centre.  <br/>  Which combination of the above is true of a body moving with constant speed in a circular track? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img8.png\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, <br/> - The acceleration is not constant, i.e its direction changes although the magnitude is constant (III is wrong), another thing that makes III wrong is the fact that the acceleration is not directed away from the centre but towards the centre. <br/> - No work is done on a body undergoing circular motion <br/> - Note that when a body is undergoing circular motion ], its velocity is not constant, i.e the direction changes, although the magnitude is constant. <br/> - Since the acceleration is directed towards the centre, the centripetal force is directed towards the centre.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity v of a particle in a time t is given by the equation  v = 10 + 2t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. Find the instantaneous acceleration after 5 seconds. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> v = 10 + 2t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> -------------------------- * <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">inst</span> = unknown <br/> N.B: Instantaneous acceleration is the acceleration of a body at any instant of time. <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a(t)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">dv<hr size=\"1\" />dt</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a(t)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">d(10+2t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)<hr size=\"1\" />dt</td></tr></table></div> <br/> a(t) = 4t ;  at t = 5s <br/> a(5) = 4(5) = 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the force and the velocity on a system are each reduced simultaneously by half, the power of the system is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced to a quarter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced by half</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> F × V = P <br/> Force × Velocity = Power ------------------------------ (i) <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">question</td><td style=\"text-align:center;\">says</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />4</td></tr></table></div> <br/> ∴ The power (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) is reduced to quarter.</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity ratio of a machine is 5 and its efficiency is 75%. What effort would be needed to lift a load of 150N with the machine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Velocity Ratio (V.R) = 5 <br/> Efficiency, (E) = 75% <br/> Load, L = 150N <br/> Effort, E = Unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall,</td><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Mechanical Advantage<hr size=\"1\" />Velocity Ratio</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">75</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />5</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> 375 = M.A × 100 <br/> M.A = 3.75 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<hr size=\"1\" />E</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3.75</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">150<hr size=\"1\" />E</td></tr></table></div> <br/> E = 40N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rope is being used to pull a mass of 10kg vertically upward. Determine the tension in the rope if, starting from rest, the mass acquires a velocity of 4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in 8s. <br/>  [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">105N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">95N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2000/img9.png\" style=\"position:relative;max-width:100%;\"/> <br/> The body is moving vertically upwards, i.e Tension (upward force), T is greater than the weight (downward force), W. <br/> The net force on the body, <br/> T - W = ma {T > W} <br/> T - mg = ma <br/> T = ma + mg -------------------- (i) <br/> v = 4ms-1 <br/> u = 0 (from rest) <br/> t = 8s <br/> Recall: v = u + at --------------- (ii) <br/> 4 = a(8) <br/> a = 0.5m/s2 <br/> Play in the value of a in (i) <br/> T = 10(0.5) + 10(10) <br/> T = 5 + 100 = 105N</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stream is flowing at 0.75ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and a boat heading perpendicular for the stream landed at the opposite bank at an angle 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>. Calculate the velocity of the boat. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.65ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.86ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A. Originally, this is how it was: <br/> <img src=\"2000/img10.png\" style=\"position:relative;max-width:100%;\"/> <br/> B. The current of the water pushes the boat, so that we now have <br/> <img src=\"2000/img11.png\" style=\"position:relative;max-width:100%;\"/> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> × cos30° = 0.75 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.86ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></td></tr></table></div></div>", "topic": "SCALARS AND VECTORS : RELATIVE VELOCITY"}, {"id": "objective>Physics>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. coherence  <br/> II. same frequency  <br/> III. Same wavelength  <br/> IV. Same intensity. <br/> Which of the condition above are necessary to produce interference fringes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that <br/> - Coherence <br/> - Equal Frequency and  <br/> - Amplitude (or wavelength) are necessary to produce interference fringes.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An engineer intends to deviate a light ray from its path by 120° through reflection from a plane mirror. Calculate the angle of incidence. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img12.png\" style=\"position:relative;max-width:100%;\"/> <br/> i → incidence angle <br/> r *arrow* reflection angle <br/> i + g = 90° ------------- (1) <br/> D = 2g ---------------- (2) <br/> D = angle of deviation <br/> Given: <br/> Angle of deviation, D = 120° <br/> 120° = 2g {From (2)} <br/> g = 60° <br/> {From (1)} i + 60°  = 90° <br/> i = 30° <br/>  <br/> ALTERNATIVELY <br/>  <br/> Using the deviation formula: <br/>  <br/> δ = 180° − 2i <br/>  <br/> Substitute δ = 120° <br/>  <br/> 120° = 180° − 2i <br/>  <br/> Solve for i <br/>  <br/> 2i = 180° − 120° = 60° <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">i</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60°<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30°</td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> Day 1</td><td style=\"border:1px solid black;text-align:center;\"> Day 2</td><td style=\"border:1px solid black;text-align:center;\"> Day 3 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Dry</td><td style=\"border:1px solid black;text-align:center;\"> 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td><td style=\"border:1px solid black;text-align:center;\"> 29<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></td><td style=\"border:1px solid black;text-align:center;\"> 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Wet</td><td style=\"border:1px solid black;text-align:center;\"> 22<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td><td style=\"border:1px solid black;text-align:center;\"> 22<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td><td style=\"border:1px solid black;text-align:center;\"> 21<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td></tr></table></div> <br/>  <br/> The reading above are for three consecutive days from a wet and dry bulb hygrometer. It can be concluded that the relative humidity for the three days</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase steadily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remained unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">was least on day 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased steadily</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Difference between the temperatures of the dry and wet hygrometer for: <br/>  <br/> Day 1 = 8⁰C <br/>  <br/> Day 2 = 7⁰C <br/>   <br/> Day 3 = 4⁰C  <br/>  <br/> Since Relative Humidity is inversely proportional to the Temperature, <br/>  <br/> ∴ There is a steady increase in the relative humidity between Day 1 and Day 3</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Total internal reflection occurs when light moves from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">air to water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water to glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dense medium to a less dense medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a less dense medium to a dense medium.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">These are the conditions for total internal reflection <br/> - Light rays travel from an optically dense medium to an optically less dense medium, e.g from glass to air  <br/> - Critical angle is exceeded <br/> a) <br/>  <img src=\"2000/img14.png\" style=\"position:relative;max-width:100%;\"/> <br/> i<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> → incidence angle <br/> r → refraction angle <br/>  <br/> b) <br/> <img src=\"2000/img15.png\" style=\"position:relative;max-width:100%;\"/> <br/> i<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → incidence angle <br/> c → critical angle <br/> N.B: i<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> < i<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/>  <br/> c) If the critical angle, C is exceeded, then total internal reflection occurs <br/> <img src=\"2000/img16.png\" style=\"position:relative;max-width:100%;\"/> <br/> i → angle of incidence <br/> r → angle of reflection</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One end of a long wire is fixed while a vibrator is attached to the other end. When the vibration is energized, the type of waves generated in the wire are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stationary and transverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">progressive and transverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stationary and longitudinal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">progressive and longitudinal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that when the wire (spring) is vibrated, there is a formation of a stationary wave. <br/> Recall: Sound wave is a wave produced whenever an elastic medium is disturbed; so when the wire is vibrated (disturbed) a sound wave will be propagated within the wire <br/> N.B: Sound wave is longitudinal in nature <br/> (a) <br/> <img src=\"2000/img17.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> b) <br/> <img src=\"2000/img18.png\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sonometer wire is vibrating at frequency f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>. If the tension in the wire is doubled while the length and the mass per unit length are kept constant, the new frequency of vibration is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>/√ 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>√ 2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is a formula that connects frequency, tension, mass per unit length, But let us first look at how a sonometer wire makes its natural frequency, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/> <img src=\"2000/img19.png\" style=\"position:relative;max-width:100%;\"/> <br/> L = NA + AN ------------------- *  <br/> L = NA + AN <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">λ<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">λ<hr size=\"1\" />2</td><td style=\"text-align:center;\">;</td><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2L</td><td style=\"text-align:center;\">------------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />2L</td><td style=\"text-align:center;\">-------------------</td><td style=\"text-align:center;\"><strong></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />μ</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">--------------------</td><td style=\"text-align:center;\">(3)</td></tr></table></div> <br/> T = Tension <br/> μ = mass per unit length <br/> Connect </strong> and (3) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2L</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />μ</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">(4)</td></tr></table></div> <br/> From the question <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> L and μ = constant <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = unknown <br/> F α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> if L and μ are constant <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">1&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> × F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> </div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy observes a piece of stone at the bottom of a river 6.0m deep. If he looks from the surface of the river, what is the apparent distance of the stone from him.  <br/> [Refractive index of water = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">4</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question tests your knowledge of refractive index <br/> * At times when you look at objects in a liquid , this appears to be closer than they really are  <br/> <img src=\"2000/img20.png\" style=\"position:relative;max-width:100%;\"/> <br/> N.B:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Refractive</td><td style=\"text-align:center;\">index</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">liquid</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Real depth<hr size=\"1\" />Apparent depth</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />x</td></tr></table></div> <br/> 4x = 18 <br/> x = 4.5m</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will allow the flow of electrons? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">candle wax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wood</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metals generally allow the flow of electrons, which enables electrical conductivity in these substances <br/> - Copper being a metal allows flow of electrons.</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The diagram above shows a maximum and minimum thermometer divided into three portions P, Q and R. Which of the following is true about the respective content of P, Q and R?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alcohol, mercury and alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air, alcohol and mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mercury, alcohol and mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air,mercury and alcohol</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In six's minimum and maximum thermometer, minimum temperature is measured by the contraction of alcohol, and maximum temperature is measured by the expansion of mercury. <br/> <img src=\"2000/img21.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main reason for making the cover of a vacuum flask airtight is to prevent heat loss by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radiation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">convection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cover of a vacuum flask is made airtight to prevent heat loss by convection. Convection is the heat transfer due to the bulk movement of molecules within fluids such as gases and liquids, including molten rock (rhyolite). It includes sub-mechanisms of advection (often also termed convection), diffusion, conduction and radiation.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A travelling wave moving from left to right has an amplitude of 0.15m, a frequency of 550 Hz and a wavelength of 0.01m. The equation describing the wave  <br/> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">y = 0.15 sin 200π(x - 5.5t)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y = 0.15 sinπ(0.01x-5.5t) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">y = 0.15sin 5.5π(x-200t)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y = 0.15 sinπ(550x-0.01t)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Amplitude: A = 0.15m <br/> Frequency f = 550Hz <br/> Wavelength λ = 0.01m <br/> <img src=\"2000/img22.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: The equation of a progressive wave <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin</td><td style=\"text-align:center;\">2π<hr size=\"1\" />λ</td><td style=\"text-align:center;\">(x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">Vt)</td><td style=\"text-align:center;\">--------------*</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.15sin</td><td style=\"text-align:center;\">2π<hr size=\"1\" />0.01</td><td style=\"text-align:center;\">(x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">Vt)</td><td style=\"text-align:center;\">---------------------</td><td style=\"text-align:center;\">**</td></tr></table></div> <br/> Recall: V = fx <br/> V = 550(0.01) <br/> V = 5.5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> y = 0.15sin200π(x - 5.5t)</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transverse wave is applied to a string whose mass per unit length is 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If the string is under tension of 12N, the speed of propagation of the wave is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> Velocity, V in a vibrating string is given as  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />μ</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> T = Tension <br/> μ = Mass per unit length <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">12<hr size=\"1\" />3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">12<hr size=\"1\" />3×0.01</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> V = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">400&nbsp;</span> = 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A quantity of water at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is heated to about 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. At each degree rise in temperature, its density will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rise steadily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise then fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall steadily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall and then rise</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Normally, when liquids are heated, their density decreases as the heating temperature increases. But, water deviates from this normal trend between 0°C and 4°C. The density of water increases with temperature between 0°C and 4°C, then from 4°C upwards, it follows the normal pattern. <br/> <img src=\"2000/img23.png\" style=\"position:relative;max-width:100%;\"/> <br/> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> from the graph, it rises and then falls </div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A thin wire with heavy weights attached to both ends hung over a block of ice resting on two supports. If the wire cuts through the ice block while the block remains solid behind the wire, the process is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regelation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This process is called REGELATION. It is a process by which melting point is increased by exerting (increasing) pressure.</div>", "topic": "CHANGE OF STATE : MELTING"}, {"id": "objective>Physics>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell of internal resistance 0.01Ω can be measured accurately using the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ohmmeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potentiometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electroscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metre bridge</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The internal resistance of a cell can be accurately measured using a potentiometer. A potentiometer is a three-terminal resistor with a sliding or rotating contact that forms an adjustable voltage divider. It can measure electric potential (voltage) accurately without causing any current to flow through the part of the circuit being measured. Therefore, the correct option is 2.</div>", "topic": "CURRENT ELECTRICITY : POTENTIOMETER"}, {"id": "objective>Physics>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electron of charge 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C and mass 9.1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span>kg is accelerated between two metal plates with a velocity of 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the potential difference between the plates is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.10 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Charge of electron, Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = 1.60 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C <br/> Mass of electron, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 9.1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span>kg <br/> Velocity, V = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Potential difference, v/p.d = unknown <br/> <img src=\"2000/img24.png\" style=\"position:relative;max-width:100%;\"/> <br/> Note: K.E electron = Electrical work <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">QV</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">9.1</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.60</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span></td></tr></table></div> <br/> 4.55 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span> × 16 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> = 1.60 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">72.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-17</span><hr size=\"1\" />1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td></tr></table></div>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span> = 4.55 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>V</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, a beam of white light travels from a rare to a dense medium. What colours of light do the rays a, b and c respectively represent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Blue yellow and red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green, red and blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red, green and blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow, blue and red</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is a concept in optics which is known as DISPERSION OF WHITE LIGHT. Dispersion of white light occurs when a white light is allowed to pass through a prism and it gets refracted into seven colours (its colourd constituents) <br/> <img src=\"2000/img25.png\" style=\"position:relative;max-width:100%;\"/> <br/> R = Red <br/> O = Orange <br/> Y = Yellow <br/> G = Green <br/> B = Blue <br/> I = Indigo <br/> V = Violet <br/> Note: These components of white move at different speed once they get air-glass boundary; and this determines their extent of deviation. In accordance with what we have in the diagram above, red deviated the least because it has the greatest energy while violet deviates the most because it has the least energy. <br/> - Let us focus on the options given <br/> a) This does not follow the order <br/> b) This does not follow the order  <br/> c) It follows the normal pattern, i.e red comes before green, and green comes before blue <br/> d) This does not follow the order <br/> </div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows two capacitors P and Q of capacitances 5µF and 10µF. Find the charges stored in P and Q respectively.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200µC and 100µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100µC and 200µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4µC and 2µC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2µC and 4µC</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img26.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: Q = CV <br/> Q = change <br/> C = Capacitance <br/> V = Voltage/ Potential difference <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> × V --------------------- * <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = (5 + 10)20 <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 300μC <br/> \" I hope you know why C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = (5 + 10)? \" This is because the capacitors are in parallel. <br/> Recall: If two or more resistors are arranged in parallel, they have the same voltage but different charges <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td></tr></table></div> <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> V = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> For the 5μF capacitor  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>C or 100μC <br/> For the 10μF capacitor <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />10×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 200 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> = 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>C or 200μC</div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What optical instrument can be constructed with converging lenses of focal lengths 50cm and 5cm?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Compound microscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terrestrial telescope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Astronomical telescope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Galileo's telescope</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question tests our knowledge on microscope and telescope construction. For the question, we have an instrument that has the converging lenses (convex lens) such that one has a longer focal length than the other <br/> <img src=\"2000/img27.png\" style=\"position:relative;max-width:100%;\"/> <br/> This construction principle is that of an astronomical telescope. In this device f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> > f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a charged ion goes through combined electric and magnetic fields, the resultant emergent velocity of ion is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">E</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">B</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">EB</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">B</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">E</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">E - B</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a charged ion goes through combined electric and magnetic fields, the resultant emergent velocity of the ion is  <br/> qE = qVB <br/>  E = BV;  <br/>  V = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">E</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">B</span> </div>", "topic": "MAGNETIC FIELD : FORCE ON A CURRENT-CARRYING CONDUCTOR"}, {"id": "objective>Physics>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the values of V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1V and 1/3V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/3V and 1V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/3V and 2/3V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1V and 2/3V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img28.png\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram given: <br/> E = 2Ω <br/> r = 1Ω <br/> Since the resistors are connected in series, <br/> Re = 3Ω + 2Ω = 5Ω <br/> Recall: E = V + Ir <br/> 2 = V + Ir <br/> From Ohm's Law, V = IR <br/> 2 = IR + Ir <br/> 2 = I(R + r) <br/> 2 = I(5 + 1) <br/> I = 2/6A --------------- * <br/> Recall that when two resistors are connected in series, the same current flows through them; <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1V</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">V</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW"}, {"id": "objective>Physics>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A projection lantern is used to give the image of a slide on a screen. If the image is 24 times as large as the slide and the screen is 72.0m from the projecting lens, what is the position of the slide from the lens? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.3m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the question given; <br/> Magnification, M = 24;  <br/> V = 72M;  <br/> U = Unknown <br/> <img src=\"2000/img29.png\" style=\"position:relative;max-width:100%;\"/> <br/>  V = 24u;  <br/> then 72 = 24u;  <br/>  U = 72/24  <br/> U = 3.0m.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radio is operated by eight cells each of e.m.f. 2.0V connected in series, if two of the cells are wrongly connected, the net e.m.f. of the radio is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8V</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2000/img30.png\" style=\"position:relative;max-width:100%;\"/> <br/> The question says if two cells are connected wrongly <br/> <img src=\"2000/img31.png\" style=\"position:relative;max-width:100%;\"/> <br/> In a cell that is rightly connected, two similar poles should not come side by side. <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 2v + 2v + 2v + 2v + 2v + 2v + (2v - 2v)   [(2v - 2v) due to wrong connection] <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 12V</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2H inductor has negligible resistance and is connected to a 50/π Hz a.c supply. The reactance of inductor is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">100</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">π</span> Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">25</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">π</span> Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Inductance, L = 2H <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Frequency,</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50<hr size=\"1\" />π</td><td style=\"text-align:center;\">Hz</td></tr></table></div> <br/> Reactance on the inductor (Inductive reactance), X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = unknown <br/> Recall; X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2πfl; X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = Inductive Reactance  <br/>  X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 2π x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">50</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">π</span> x 2  = 200Ω.</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the fraction of the atoms of a radioactive material left after 120 years is 1/64, what is the half-life of the material?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24 years</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let half life be represented as T and mass be M. <br/> After 1 T, remaining mass equals M/2 <br/> After 2T, remaining mass equals M/4 <br/> After 3T, remaining mass equals M/8 <br/> After 4T, remaining mass equals M/16 <br/> After 5T, remaining mass equals M/32 <br/> After 6T, remaining mass equals M/64 <br/>  <br/> Therefore,  <br/> 6T = 120 <br/> T = 120/6 <br/> T = 20 years <br/> </div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain radioactive source emits radiations that were found to be deflected by both magnetic and electric fields. The radiations are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">x-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beta rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ultra-violent rays</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Any radiation that has the ability to be deflected by both electric and magnetic field is said to be electromagnetic in nature. <br/> N.B: X-rays are electromagnetic waves and not radiation <br/> U - V rays are electromagnetic waves and not radiation <br/> Gamma rays are electromagnetic radiations that can be emitted from a radioactive source.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a pure semiconductor, the number of electrons in the conduction band is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Equal to the number of holes in the valence band</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than the number of holes in the valence band</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the number of holes in the valence band</div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice the number of holes in the valence band</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a pure semiconductor, the number of electrons in the conduction band is equal to the number of holes in the valence band. </div>", "topic": "INTRODUCTORY ELECTRONICS : INTRINSIC AND EXTRINSIC SEMI-CONDUCTORS"}, {"id": "objective>Physics>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell of internal resistance 1Ω supplies current to an external resistor of 3Ω. The efficiency of the cell is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Internal resistance, r = 1Ω <br/> External resistor, R = 3Ω <br/> Efficiency, E = Unknown <br/> <img src=\"2000/img32.png\" style=\"position:relative;max-width:100%;\"/> <br/> From the circuit above <br/> E = V + Lv ------------- * <br/> E = E.m.f of the cell <br/> V = Potential difference across the resistor <br/> Lv = Lost volt <br/> N.B: E.m.f is like the work input <br/> Potential difference is like useful work output. <br/> Lost volt is like workdone to overcome the internal resistance of the cell. <br/> E = V + lv ----------------- * * But V = IR and Lv = Ir) <br/> E = IR + Ir <br/> E = I(R + r) ----------------- * * * <br/> Recall: The efficiency of a cell is given as <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />E</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">IR<hr size=\"1\" />I(R+r)</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div>= 75%</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Light of energy 5 eV falls on a metal of work function 3 ev and electrons are liberated. The stopping potentials is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15 0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NOTE: Stopping potential = E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Stopping P.d = 5eV - 3eV = 2eV <br/> E = 2ev <br/> 2 x 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/>  = 3.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">eVs</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.2x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span><hr size=\"1\" />1.6x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td></tr></table></div> <br/> Vs = 2.0v</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a thermonuclear reaction, the total initial mass is 5.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span>kg and the total final mass is 5.01 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span>kg. The energy released in the process is <br/> [c = 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-13</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Initial mass, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 5.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span>kg <br/> Final mass, mf = 5.01 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span>kg <br/> Δm = 0.01 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-27</span>kg = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-29</span>kg <br/> Recall: E = mc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>------------------- * <br/> E = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-29</span> × ( 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> )<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> E = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-29</span> × 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span> <br/> E = 9.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-13</span>J</div>", "topic": "ELEMENTARY MODERN PHYSICS : BINDING ENERGY, MASS DEFECT AND EINSTERIN’S ENERGY EQUATION"}, {"id": "objective>Physics>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The magnetic flux in a coil having 200 turns changes at the time rate of 0.08Wbs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The induced e.m.f. in the coil is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.6V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250.0V</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Number of turns = 200 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">dθ<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.08Wbs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> Induced emf = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">E.m.f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">dθ<hr size=\"1\" />dt</td></tr></table></div> <br/> E = 200 × 0.08 = 16v </div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the frequency of an emitted x-rays is 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>Hz, the accelerating potential is  <br/> [e = 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C, h = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.6V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66.3V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">663.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6630.0V</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Frequency of emission f = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>Hz <br/> Charge of an electron, e = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C <br/> Planck's constant, h = 6.63 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js <br/> Accelerating potential, V = unknown <br/> Recall: E = hf------------------------- * <br/> Qv = hf <br/> eV = hf;  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">hf<hr size=\"1\" />e</td><td style=\"text-align:center;\"></td></tr></table></div> = 6.63 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> x 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span> / 1.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>  <br/>  V = 66.3V</div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The correct position for a fuse in the diagram above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between P and Q</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagramatically, this is what we have, <br/>  <br/> In a plug, the blue neutral wire goes to the left, the brown live wire to the right and yellow stripped earth wire is on top. The fuse fits next to the live wire. <br/>  <br/> A fuse must be connected to the live wire side so as to ensure that it keeps high voltage from reaching the user or surrounding if a fault develops</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the a.c circuit above, the current value is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.67A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.00A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.58A</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given the diagram:  <br/> <img src=\"2000/img33.png\" style=\"position:relative;max-width:100%;\"/> <br/> Effective voltage, V = 200V <br/> Effective resistance (Impedance), Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span>Z = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> = 50Ω <br/> Recall: V = IR <br/> V = IZ <br/> 200 = I × 50 <br/> I = 4.00A</div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> If current flows in the direction of the arrows in the solenoid above, the north pole is at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the current flows in the direction of the arrows in the solenoid then the north pole is at Q</div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas would serve as an electrical conductor under </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduced pressure and high potential difference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced pressure and high current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased magnetic field</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exposure to visible light</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The condition under which a gas can conduct electricity are just two -  <br/> (1) Low pressure <br/> (2) High potential difference (high current)</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric generator with a power output of 3.0 kW at voltage of 1.5kV distributes power along cables of total resistance 20.0Ω. The power loss in the cable is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.1W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.0W</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Power output of the generator, P = 3.0KW <br/> Voltage, V = 1.5kv <br/> To get the power loss in the cable of total resistance 20.0Ω, we need to get the current the generator supplies to the cables <br/> <img src=\"2000/img34.png\" style=\"position:relative;max-width:100%;\"/> <br/> Assume that there are 3 cables and their resultant/effective resistance gives 20.0Ω <br/> <img src=\"2000/img35.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: P = IV <br/> 3 = I × 1.5 <br/> I = 2.0A <br/> <img src=\"2000/img36.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × R <br/> P = 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 20 = 80W</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A conductor of length 2m carries a current of 0.8A while kept in a magnetic field of magnetic flux density 0.5T. The maximum force acting on it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Length, L = 2.0m <br/> Current, I = 0.8A <br/> Magnetic Flux Density, B = 0.5T <br/> Force, F = Unknown <br/> Recall; F = BIL  <br/>  F = 0.5 × 0.8 × 2  <br/>  F = 0.8N.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}];
